// html`&lt;br&gt;&lt;p&gt;&lt;strong&gt;Table layout&lt;/strong&gt;&lt;/p&gt;`

// Border
viewof st_table_border = Inputs.form({
  border_color: Inputs.color({
    label: "Table border color",
    value: "#000000"
  }),
  border_size: Inputs.range([0, 3], {
    step: 0.1,
    label: "Table border size (px)",
    value: 1  
  })
})









// html`&lt;br&gt;&lt;p&gt;&lt;strong&gt;Table header&lt;/strong&gt;&lt;/p&gt;`

// Header
viewof st_table_header = Inputs.form({
  bg_color: Inputs.color({
    label: "Table header background color",
    value: "#021b97"
  }),
  font_color: Inputs.color({
    label: "Table header text color",
    value: "#f0f2ff"
  }),
  font_size: Inputs.range([0.5, 2], {
    step: 0.1,
    label: "Table header font size (em)",
    value: 1  
  })
})








// html`&lt;br&gt;&lt;p&gt;&lt;strong&gt;Table body&lt;/strong&gt;&lt;/p&gt;`

// Body
viewof st_table_body = Inputs.form({
  bg_color: Inputs.color({
    label: "Table body background color",
    value: "#ffffff"
  }),
  font_color: Inputs.color({
    label: "Table body text color",
    value: "#021b97"
  }),
  font_size: Inputs.range([0.5, 2], {
    step: 0.1,
    label: "Table body font size (em)",
    value: 1  
  })
})
viewof st_table_body_odd_rows_bg_color = Inputs.color({
    label: "Table odd row background color",
    value: "#ffffff"
})

viewof st_table_body_even_rows_bg_color = Inputs.color({
    label: "Table even row background color",
    value: "#ffffff"
})





























// html`&lt;br&gt;&lt;p&gt;&lt;strong&gt;Inner tables&lt;/strong&gt;(tables in columns)&lt;/p&gt;`

// Inner tables
viewof st_table_inner_table = Inputs.form({
  bg_color: Inputs.color({
    label: "Inner table border color",
    value: "#ffffff"
  }),
  border_size: Inputs.range([0, 3], {
    step: 0.1,
    label: "Table border size (px)",
    value: 1  
  })
})
// Inner plots (bar graphs) --&gt; .st-table tbody td img.img-fluid{}
viewof st_table_inner_graph = Inputs.form({
  bg_color: Inputs.color({
    label: "Graph bg color",
    value: "#ffffff"
  }),
  border_radius: Inputs.range([0, 50], {
    step: 0.5,
    label: "Graph border radius",
    value: 0  
  }),
  padding: Inputs.range([0, 50], {
    step: 0.5,
    label: "Graph padding",
    value: 0  
  }),
  margin: Inputs.range([0, 50], {
    step: 0.5,
    label: "Graph margin",
    value: 0  
  })
})





















import {Copier} from "@mbostock/copier"

Copier("Copy CSS to clipboard", {value: cssText})
















// cssText
html`&lt;pre&gt;&lt;code&gt;${cssText}&lt;/code&gt;&lt;/pre&gt;`







// Generate CSS text
cssText = `
/* Table layout */
.st-table {
  border: ${st_table_border.border_size}px solid ${st_table_border.border_color};
}

/* Table header */
.st-table thead th, .st-table tr.header th {
  color: ${st_table_header.font_color};
  background-color: ${st_table_header.bg_color};
  font-size: ${st_table_header.font_size}em;
}

/* Table body */
.st-table tbody td {
  color: ${st_table_body.font_color};
  background-color: ${st_table_body.bg_color} !important;
  font-size: ${st_table_body.font_size}em;
}

/* Table body rows */

/* Odd rows */
.st-table tr:nth-child(odd) td {
  /* background: ${st_table_body_odd_rows_bg_color}; */ 
  background-color: ${st_table_body_odd_rows_bg_color}; 
}

/* Even rows */
.st-table tr:nth-child(even) td {
  background: ${st_table_body_even_rows_bg_color}; 
}

/* Inner (column) tables */
.st-table tbody .table-sm {
  background: ${st_table_inner_table.bg_color} !important;
  border: ${st_table_inner_table.border_size}px solid #000000;
  /* border-collapse: collapse; */
}

/* Inner table graph */
.st-table tbody td img.img-fluid {
  background-color: ${st_table_inner_graph.bg_color} !important;
  border-radius: ${st_table_inner_graph.border_radius}px !important;
  padding: ${st_table_inner_graph.padding}px !important;
  margin: ${st_table_inner_graph.margin}px !important;
}
`
// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~







// DO NOT DELETE
// Apply CSS from inputs to entire document
html`&lt;style&gt;
${cssText}
&lt;/style&gt;
`
















